using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration – set these environment variables before running:
//   OPENAI_API_KEY   (required)
//   OPENAI_MODEL     (optional, defaults to gpt-4o-mini)
//   SEARCH_API_KEY   (optional – Brave Search API key; when absent the
//                     search tool returns a placeholder result so you can
//                     still see the agent loop in action)
// ---------------------------------------------------------------------------
var apiKey  = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
              ?? throw new InvalidOperationException("Set the OPENAI_API_KEY environment variable.");
var model   = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()   // automatically invoke tools when the model requests them
    .Build();

// ---- Tools ----------------------------------------------------------------
var notebook  = new Notebook();
var webSearch = new WebSearchTool();

var tools = new ChatOptions
{
    Tools =
    [
        AIFunctionFactory.Create(webSearch.SearchAsync),
        AIFunctionFactory.Create(notebook.AddNote),
        AIFunctionFactory.Create(notebook.GetNotes),
    ],
};

// ---- Conversation loop ----------------------------------------------------
var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍  Researching: {topic}\n");

List<ChatMessage> history =
[
    new(ChatRole.System, """
        You are a research agent. The user will give you a topic.
        1. Use the **search_web** tool to find relevant information (make 2-3 searches with varied queries).
        2. Use **add_note** to save each important finding as a concise note.
        3. After gathering enough information, call **get_notes** to review what you collected.
        4. Finally, write a well-structured summary of your research for the user.
        Be thorough but concise.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a summary: {topic}"),
];

var response = await chatClient.GetResponseAsync(history, tools);

Console.WriteLine("\n────────────────────────────────────────");
Console.WriteLine("📝  Research Summary");
Console.WriteLine("────────────────────────────────────────\n");
Console.WriteLine(response.Text);
Console.WriteLine();

// ---- Helpers --------------------------------------------------------------
static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine()?.Trim();
    return string.IsNullOrEmpty(input)
        ? "Recent advances in quantum computing"
        : input;
}

// ===========================================================================
//  Tool implementations
// ===========================================================================

/// <summary>Simple in-memory notebook that the agent uses to collect findings.</summary>
sealed class Notebook
{
    private readonly List<string> _notes = [];

    [Description("Save a research note. Use this to record an important finding.")]
    public string AddNote(
        [Description("The note text to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📌  Note saved ({_notes.Count} total)");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join('\n', _notes.Select((n, i) => $"{i + 1}. {n}"));
    }
}

/// <summary>Web search tool backed by Brave Search API (or a placeholder when no key is set).</summary>
sealed class WebSearchTool
{
    private static readonly HttpClient Http = new();
    private readonly string? _braveApiKey = Environment.GetEnvironmentVariable("SEARCH_API_KEY");

    [Description("Search the web for information on a query. Returns a list of result snippets.")]
    public async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🌐  Searching: \"{query}\"");

        if (_braveApiKey is not null)
            return await BraveSearchAsync(query);

        // Fallback: return a placeholder so the agent loop still works without an API key.
        return $"""
            [Simulated search results for "{query}"]
            1. "{query}" - Wikipedia overview: Provides a general introduction and history.
            2. Recent News: Latest developments and breakthroughs related to {query}.
            3. Academic Paper: A 2025 survey paper covering the state of the art in {query}.
            (Set the SEARCH_API_KEY env var to a Brave Search API key for real results.)
            """;
    }

    private async Task<string> BraveSearchAsync(string query)
    {
        var request = new HttpRequestMessage(HttpMethod.Get,
            $"https://api.search.brave.com/res/v1/web/search?q={Uri.EscapeDataString(query)}&count=5");
        request.Headers.Add("X-Subscription-Token", _braveApiKey);
        request.Headers.Add("Accept", "application/json");

        var response = await Http.SendAsync(request);
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.CreateAsync(await response.Content.ReadAsStreamAsync());
        var results = doc.RootElement.GetProperty("web").GetProperty("results");

        var snippets = new List<string>();
        foreach (var r in results.EnumerateArray())
        {
            var title = r.GetProperty("title").GetString();
            var snippet = r.TryGetProperty("description", out var d) ? d.GetString() : "";
            var url = r.GetProperty("url").GetString();
            snippets.Add($"- {title}: {snippet} ({url})");
        }

        return string.Join('\n', snippets);
    }
}

