 /// <summary>Web search tool backed by Brave Search API (or a placeholder when no key is set).</summary>
 sealed class WebSearchTool
 {
     private static readonly HttpClient Http = new();
     private readonly string? _braveApiKey = Environment.GetEnvironmentVariable("SEARCH_API_KEY");

     [Description("Search the web for information on a query. Returns a list of result snippets.")]
     public async Task<string> SearchAsync(
         [Description("The search query")] string query)
     {
         Console.WriteLine($"  🌐  Searching: \"{query}\"");

         if (_braveApiKey is not null)
